def researcher(topic):
    return f"[Notes] {topic} is a popular framework for building user interfaces."

def writer(notes):
    return f"[Draft] Did you know? {notes}"

def reviewer(draft):
    return f"[Final Polish] Here is the article: {draft}"

def run_crew(topic):
    step1 = researcher(topic)
    step2 = writer(step1)
    step3 = reviewer(step2)
    return step3

final_output = run_crew("React")
print(final_output)
